parameters.jsCode:
try {
  const raw = typeof query === 'object' && query !== null
    ? (query.precio ?? query.query ?? query.value ?? query)
    : query;
  const num = Number(raw);
  if (!Number.isFinite(num)) {
    return JSON.stringify({ error: 'Valor no numérico', recibido: String(raw) });
  }
  const result = Math.floor(num / 10) * 10;
  return String(result);
} catch (e) {
  return JSON.stringify({ error: (e && e.message) || 'Error en ajustar_precio' });
}

